import mongoose from 'mongoose';
import * as dotenv from 'dotenv';
import dns from 'dns';

dotenv.config();
dns.setDefaultResultOrder('ipv4first');
dns.setServers(['8.8.8.8', '8.8.4.4']);

const GraphNodeSchema = new mongoose.Schema({
  nodeId:    { type: String, required: true, unique: true },
  lat:       { type: Number, required: true },
  lng:       { type: Number, required: true },
  label:     { type: String },
  destinoId: { type: String, default: null },
  tipo:      { type: String, enum: ['destino', 'interseccion', 'auxiliar'], default: 'destino' },
}, { timestamps: true, collection: 'graph_nodes' });

const GraphEdgeSchema = new mongoose.Schema({
  from:      { type: String, required: true },
  to:        { type: String, required: true },
  distance:  { type: Number, required: true },
  waypoints: [{ lat: { type: Number }, lng: { type: Number } }],
}, { timestamps: true, collection: 'graph_edges' });

const GraphNode = mongoose.model('GraphNode', GraphNodeSchema);
const GraphEdge = mongoose.model('GraphEdge', GraphEdgeSchema);

