async function main() {
  if (!process.env.MONGO_URI) { console.error('MONGO_URI no está en .env'); process.exit(1); }
  await mongoose.connect(process.env.MONGO_URI, {
    dbName: process.env.DB_NAME || 'NovaCode',
    serverSelectionTimeoutMS: 15000, socketTimeoutMS: 45000, family: 4,
  });
  console.log('✅ MongoDB conectado');

  await GraphNode.deleteMany({});
  await GraphEdge.deleteMany({});
  console.log('🗑  Colecciones limpiadas');

  for (const n of NODES) {
    await GraphNode.create(n);
  }
  console.log(`✅ ${NODES.length} nodos insertados`);

  for (const e of EDGES) {
    await GraphEdge.create({ from: e.from, to: e.to, distance: e.distance, waypoints: e.waypoints });
    await GraphEdge.create({ from: e.to, to: e.from, distance: e.distance, waypoints: [...e.waypoints].reverse() });
  }
  console.log(`✅ ${EDGES.length * 2} aristas insertadas (${EDGES.length} rutas reales)`);

  await mongoose.disconnect();
  console.log('✅ Listo');
}

main().catch(console.error);